'use client';

import { useEffect, useState } from 'react';
import { ReactFlowProvider } from 'reactflow';
import { useOSStore } from '@/store/osStore';
import { DeploymentGuard } from '@/components/DeploymentGuard';
import { RibbonBar } from '@/components/os/RibbonBar';
import { Taskbar } from '@/components/os/Taskbar';
// import FlowCanvas from '@/components/flow/FlowCanvas'; // Now a window
// import { AluCAD } from '@/cad/components/AluCAD'; // Now a window
import { WelcomeModal } from '@/components/os/WelcomeModal';
import { bootKernel } from '@/core/kernel';
import { Hexagon } from 'lucide-react';
// import CuttingOptimizer from '@/components/CuttingOptimizer'; // Now a window
import { StartMenu } from '@/components/os/StartMenu';
// MusicPlayer removed
import dynamic from 'next/dynamic';
import { WindowManager } from '@/components/os/WindowManager';
import { getDictionary } from '@/get-dictionary';
import { UnifiedDock } from '@/components/modules/desk/UnifiedDock';
import { GlobalUtilityLayer } from '@/components/os/GlobalUtilityLayer';

const DeskCanvas = dynamic(() => import('@/components/modules/desk/DeskCanvas'), { ssr: false });

/**
 * OS Page - Unified Desk Architecture
 * 
 * "Desk" is the primary environment (wallpaper/whiteboard).
 * All other apps (CAD, Flow, FEA) run as windows on top.
 */
export default function OSPage() {
    // Hardcoded to 'en' since we removed i18n routing
    const lang = 'en';

    const {
        setDictionary,
        setLanguage,
        theme,
        dictionary,
        windows, // Get windows
        activeWindowId, // Get active ID
        workspaceMode,
        startMenuOpen,
        toggleStartMenu,
        setStartMenuOpen
    } = useOSStore();
    const [mounted, setMounted] = useState(false);

    // ... (rest of useEffects)

    // Derived state for Ribbon visibility
    const activeWindow = windows.find(w => w.id === activeWindowId);
    // Hide ribbon if we are in 'desk' mode (utility apps) and the active window is maximized.
    // We KEEP the ribbon for CAD/CAM/Flow/FEA even if maximized, as they need their toolbars.
    const hideRibbon = activeWindow?.maximized && workspaceMode === 'desk';

    if (!mounted) {
        // ... (loading state)
    }

    return (
        <ReactFlowProvider>
            <div
                className="flex flex-col w-screen h-screen overflow-hidden bg-[var(--color-os-canvas)] text-slate-200"
                data-theme={theme}
            >
                {/* 1. Header / App Launcher - Hidden in Focus Mode */}
                {!hideRibbon && (
                    <div className="flex flex-col shrink-0 z-50">
                        {/* RIBBON BAR (Property Tools) - Now at Top */}
                        <RibbonBar mode={workspaceMode} dock={true} />
                    </div>
                )}



                {/* 2. Main Workspace (Desk is always the background) */}
                <div className="flex-1 relative overflow-hidden">

                    {/* A. Creative Desk Layer (Background) */}
                    <div className="absolute inset-0 z-0">
                        <DeskCanvas />
                    </div>

                    {/* B. Window Layer (Applications) */}
                    <div className="absolute inset-0 z-10 pointer-events-none">
                        {/* Pointer events none allows clicking through to desk, 
                                but Windows themselves typically have pointer-events-auto */}
                        <WindowManager />
                    </div>
                </div>

                <UnifiedDock />

                {/* Floating Node Navigator (Only in Flow) */}
                <Taskbar />

                {/* 4. Onboarding Modal */}
                <WelcomeModal />

                {/* 5. Start Menu */}
                <StartMenu
                    isOpen={startMenuOpen}
                    onClose={() => setStartMenuOpen(false)}
                />

                {/* 6. Global Utility Layer (Calc, Unit Conv) */}
                <GlobalUtilityLayer />
            </div>
        </ReactFlowProvider>
    );
}
