'use client';

import React from 'react';
import { useOSStore } from '@/store/osStore';
import {
    Grid3X3, Move3d, Box, Layout, Activity,
    Music, Calculator, ArrowLeftRight, MessageSquare, PenTool, BookOpen, Settings, Globe
} from 'lucide-react';
// import { useMusicPlayerStore } from '@/store/musicPlayerStore';
import { useUtilityStore } from '@/store/utilityStore';
import { motion } from 'framer-motion';
import { AluLogo } from '@/components/ui/AluLogo';

/**
 * 🛠️ UNIFIED DOCK (OS Controls)
 */
export function UnifiedDock() {
    const { openWindow, workspaceMode, windows, activeWindowId } = useOSStore();
    const {
        isCalcOpen, isUnitOpen, isSettingsOpen, isFeedbackOpen, isLanguageOpen,
        toggleCalc, toggleUnit, toggleSettings, toggleFeedback, toggleLanguage
    } = useUtilityStore();

    return (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-[99999] flex items-center gap-4 pointer-events-auto">

            {/* 1. START BUTTON (Left) */}
            <motion.button
                onClick={() => useOSStore.getState().toggleStartMenu()}
                className="group relative flex items-center justify-center w-12 h-12 rounded-2xl bg-[#0f1419]/90 border border-[#2a3a4a] shadow-2xl backdrop-blur-xl transition-all duration-300 active:scale-95"
                whileHover={{ scale: 1.1, borderColor: 'rgba(34,211,238,0.5)' }}
                whileTap={{ scale: 0.95 }}
                title="Start Menu"
            >
                {/* Animated Logo */}
                <AluLogo size={28} className="drop-shadow-[0_0_15px_rgba(34,211,238,0.6)]" />
            </motion.button>

            {/* 2. Main Navigation Dock Container */}
            <div
                className="flex items-center gap-1 p-2 rounded-2xl border border-[#2a3a4a] shadow-2xl backdrop-blur-xl"
                style={{ backgroundColor: 'rgba(15, 20, 25, 0.95)' }}
            >

                {/* Section 1: Workstations (Primary Apps) */}
                <div className="flex items-center gap-1 pr-2 border-r border-white/10">
                    <DockItem
                        label="Flow"
                        icon={<Layout size={20} />}
                        onClick={() => openWindow('flow-editor', true)}
                        color="cyan"
                        isActive={workspaceMode === 'flow'}
                    />
                    <DockItem
                        label="CAD"
                        icon={<Move3d size={20} />}
                        onClick={() => openWindow('cad-editor', true)}
                        color="green"
                        isActive={workspaceMode === 'cad'}
                    />
                    <DockItem
                        label="CAM"
                        icon={<Box size={20} />}
                        onClick={() => openWindow('cutting-optimizer', true)}
                        color="amber"
                        isActive={workspaceMode === 'cam'}
                    />
                    <DockItem
                        label="Sketch"
                        icon={<PenTool size={20} />}
                        onClick={() => openWindow('sketch-pad', true)}
                        color="pink"
                        isActive={windows.some(w => w.type === 'sketch-pad' && w.id === activeWindowId)}
                    />
                    <DockItem
                        label="FEA"
                        icon={<Activity size={20} />}
                        onClick={() => openWindow('simulation-fea', true)}
                        color="purple"
                        isActive={workspaceMode === 'fea'}
                    />
                    <DockItem
                        label="Eng. Handbook"
                        icon={<BookOpen size={20} />}
                        onClick={() => openWindow('handbook', true)}
                        color="green"
                        isActive={windows.some(w => w.type === 'handbook' && w.id === activeWindowId)}
                    />
                </div>

                {/* Section 2: OS Utilities (Always Accessible) */}
                <div className="flex items-center gap-1 pl-1">
                    <DockItem
                        label="Scientific Calc"
                        icon={<Calculator size={18} />}
                        onClick={toggleCalc}
                        color="default"
                        isActive={isCalcOpen}
                    />
                    <DockItem
                        label="Unit Converter"
                        icon={<ArrowLeftRight size={18} />}
                        onClick={toggleUnit}
                        color="default"
                        isActive={isUnitOpen}
                    />
                    <DockItem
                        label="Language"
                        icon={<Globe size={18} />}
                        onClick={toggleLanguage}
                        color="default"
                        isActive={isLanguageOpen}
                    />
                    <DockItem
                        label="Settings"
                        icon={<Settings size={18} />}
                        onClick={toggleSettings}
                        color="default"
                        isActive={isSettingsOpen}
                    />
                </div>
            </div>

            {/* 3. CONTACT / FEEDBACK (Right) */}
            <motion.button
                onClick={toggleFeedback}
                className={`group flex items-center justify-center w-12 h-12 rounded-2xl border shadow-2xl backdrop-blur-xl transition-all duration-300 active:scale-95 ${isFeedbackOpen
                    ? 'bg-white/20 border-blue-500/50 scale-110'
                    : 'bg-[#0f1419]/90 border-[#2a3a4a] hover:bg-white/10 hover:scale-110 hover:border-blue-500/50'
                    }`}
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.95 }}
                title="Contact & Feedback"
            >
                <motion.div
                    animate={{
                        y: isFeedbackOpen ? 0 : [0, -2, 0],
                        opacity: isFeedbackOpen ? 1 : [0.8, 1, 0.8]
                    }}
                    transition={{
                        duration: 3,
                        repeat: isFeedbackOpen ? 0 : Infinity,
                        ease: "easeInOut"
                    }}
                >
                    <MessageSquare size={22} className={isFeedbackOpen ? 'text-blue-300' : 'text-blue-400 group-hover:text-blue-300'} />
                </motion.div>
            </motion.button>
        </div>
    );
}

interface DockItemProps {
    label: string;
    icon: React.ReactNode;
    onClick: () => void;
    isActive?: boolean;
    color?: string;
}

function DockItem({ label, icon, onClick, isActive, color }: DockItemProps) {
    const colorColors: Record<string, string> = {
        cyan: 'rgba(34,211,238,1)',
        green: 'rgba(74,222,128,1)',
        amber: 'rgba(251,191,36,1)',
        purple: 'rgba(192,132,252,1)',
        pink: 'rgba(236,72,153,1)',
        default: 'rgba(255,255,255,1)'
    };

    const colorClasses: Record<string, string> = {
        cyan: 'text-cyan-400 group-hover:bg-cyan-400/20 group-hover:shadow-[0_0_15px_rgba(34,211,238,0.4)]',
        green: 'text-green-400 group-hover:bg-green-400/20 group-hover:shadow-[0_0_15px_rgba(74,222,128,0.4)]',
        amber: 'text-amber-400 group-hover:bg-amber-400/20 group-hover:shadow-[0_0_15px_rgba(251,191,36,0.4)]',
        purple: 'text-purple-400 group-hover:bg-purple-400/20 group-hover:shadow-[0_0_15px_rgba(192,132,252,0.4)]',
        pink: 'text-pink-400 group-hover:bg-pink-400/20 group-hover:shadow-[0_0_15px_rgba(236,72,153,0.4)]',
        default: 'text-gray-400 group-hover:bg-white/10 group-hover:text-white'
    };

    const activeColor = color ? colorColors[color] : colorColors.default;
    const selectedColorClass = color ? colorClasses[color] : colorClasses.default;

    return (
        <div className="relative group p-0.5">
            <button
                onClick={onClick}
                className={`
                    w-10 h-10 rounded-xl flex items-center justify-center transition-all duration-300 ease-out
                    ${isActive ? 'bg-white/20 text-white scale-110 shadow-lg' : 'hover:scale-110'}
                    ${!isActive ? selectedColorClass : ''}
                `}
                style={isActive ? {
                    boxShadow: `0 0 20px ${activeColor.replace('1)', '0.3)')}`,
                    color: activeColor
                } : {}}
                title={label}
            >
                <motion.div
                    animate={isActive ? {} : {
                        y: [0, -1.5, 0],
                        scale: [1, 1.05, 1],
                    }}
                    transition={{
                        duration: 3 + Math.random(),
                        repeat: Infinity,
                        ease: "easeInOut",
                        delay: Math.random() * 2
                    }}
                >
                    {icon}
                </motion.div>
            </button>

            {/* Tooltip */}
            <div className="absolute -top-10 left-1/2 -translate-x-1/2 px-2 py-1 bg-black/90 text-white text-[10px] rounded border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-[100000]">
                {label}
            </div>

            {/* Active Indicator dot */}
            {isActive && (
                <div
                    className="absolute -bottom-1.5 left-1/2 -translate-x-1/2 w-1.5 h-1 rounded-full"
                    style={{
                        backgroundColor: activeColor,
                        boxShadow: `0 0 8px ${activeColor}`
                    }}
                />
            )}
        </div>
    );
}
